// Validate input and set defaults
const input = $input.first().json.body || $input.first().json;

if (!input.query || typeof input.query !== 'string') {
  throw new Error('Missing or invalid query field');
}

const context = input.context || {};
const options = {
  agents: input.options?.agents || null,
  delivery: input.options?.delivery || 'audio',
  format: input.options?.format || 'standard',
  include_full_deliberation: input.options?.include_full_deliberation ?? true
};

const deliberation_id = `bod-${new Date().toISOString().slice(0,10)}-${Math.random().toString(36).slice(2,8)}`;

return {
  deliberation_id,
  query: input.query,
  context,
  options,
  start_time: Date.now()
};

const { query, context, options } = $input.first().json;

// Agent profiles with full personas
const AGENTS = {
  'Warren Buffett': {
    domain: 'Finance & Investment',
    voice: 'Folksy Omaha wisdom, baseball metaphors, long-term thinking',
    frameworks: ['Opportunity cost', 'Circle of competence', 'Margin of safety', 'Mr. Market'],
    tendencies: 'Patient, values certainty, focuses on downside protection',
    keywords: ['invest', 'capital', 'valuation', 'money', 'price', 'value', 'contract', 'deal']
  },
  'Peter Drucker': {
    domain: 'Management & Consulting',
    voice: 'Precise questioning, effectiveness over efficiency',
    frameworks: ['What business are we in?', 'Contribution focus', 'Systematic abandonment'],
    tendencies: 'Asks fundamental questions, skeptical of activity without results',
    keywords: ['consulting', 'management', 'organization', 'effectiveness', 'client']
  },
  'Nassim Taleb': {
    domain: 'Risk & Uncertainty',
    voice: 'Provocative, mathematical, anti-fragile thinking',
    frameworks: ['Optionality', 'Barbell strategy', 'Skin in the game', 'Via negativa'],
    tendencies: 'Contrarian, risk-obsessed, values asymmetric payoffs',
    keywords: ['risk', 'uncertainty', 'downside', 'fragile', 'option']
  },
  'George Marshall': {
    domain: 'Strategy & Operations',
    voice: 'Measured, probability-weighted, trade-off focused',
    frameworks: ['Resource allocation', 'Scenario planning', 'Coalition building'],
    tendencies: 'Realistic, systematic, balances competing demands',
    keywords: ['strategy', 'operations', 'plan', 'resources', 'military', 'defense']
  },
  'Theodore Roosevelt': {
    domain: 'Action & Leadership',
    voice: 'Energetic, decisive, bias to action',
    frameworks: ['Do what you can with what you have', 'Man in the arena', 'Strenuous life'],
    tendencies: 'Favors action over deliberation, accepts imperfection',
    keywords: ['action', 'do', 'start', 'execute', 'bold']
  },
  'Steve Jobs': {
    domain: 'Product & Design',
    voice: 'Intense focus on user experience, simplicity obsession',
    frameworks: ['Start with customer experience', 'Say no to 1000 things', 'Intersection of technology and liberal arts'],
    tendencies: 'Perfectionist, willing to cannibalize, values taste',
    keywords: ['product', 'design', 'user', 'experience', 'simple']
  },
  'Reid Hoffman': {
    domain: 'Entrepreneurship & Networks',
    voice: 'Network thinking, permanent beta mindset',
    frameworks: ['ABZ planning', 'Blitzscaling', 'Alliance building'],
    tendencies: 'Values speed and learning, thinks in network effects',
    keywords: ['startup', 'entrepreneur', 'network', 'scale', 'pivot']
  },
  'Clayton Christensen': {
    domain: 'Innovation & Strategy',
    voice: 'Thoughtful academic, jobs-to-be-done focus',
    frameworks: ['Disruptive innovation', 'Jobs to be done', 'Innovator\'s dilemma'],
    tendencies: 'Sees disruption patterns, questions incumbents',
    keywords: ['innovation', 'disrupt', 'strategy', 'competitive']
  },
  'Ben Horowitz': {
    domain: 'Startup Execution',
    voice: 'Direct, wartime mentality, hip-hop references',
    frameworks: ['Peacetime vs wartime CEO', 'The hard thing about hard things', 'Culture as strategy'],
    tendencies: 'Confronts brutal facts, values execution over planning',
    keywords: ['startup', 'execute', 'hard', 'ceo', 'team', 'hire']
  },
  'Admiral Stavridis': {
    domain: 'Defense & Geopolitics',
    voice: 'Strategic clarity, interagency thinking',
    frameworks: ['Smart power', 'Whole-of-government', 'Alliance management'],
    tendencies: 'Long-term strategic view, values coalition building',
    keywords: ['defense', 'military', 'government', 'security', 'dod', 'navy']
  }
};

// Route to appropriate agents
const queryLower = query.toLowerCase();
const contextStr = JSON.stringify(context).toLowerCase();

function scoreAgent(name, profile) {
  let score = 0;
  for (const kw of profile.keywords) {
    if (queryLower.includes(kw)) score += 10;
    if (contextStr.includes(kw)) score += 5;
  }
  return score;
}

let selectedAgents;
let category;
let rationale;

if (options.agents && options.agents.length === 3) {
  selectedAgents = options.agents;
  category = 'user_specified';
  rationale = 'User-specified panel';
} else {
  // Score all agents
  const scores = Object.entries(AGENTS).map(([name, profile]) => ({
    name,
    profile,
    score: scoreAgent(name, profile)
  })).sort((a, b) => b.score - a.score);

  // Take top 3, but ensure diversity
  selectedAgents = [scores[0].name];

  // Ensure we have different domains
  for (const s of scores.slice(1)) {
    if (selectedAgents.length >= 3) break;
    const existingDomains = selectedAgents.map(n => AGENTS[n].domain);
    if (!existingDomains.includes(s.profile.domain) || selectedAgents.length < 3) {
      selectedAgents.push(s.name);
    }
  }

  // If still need more, just take top scored
  while (selectedAgents.length < 3) {
    for (const s of scores) {
      if (!selectedAgents.includes(s.name)) {
        selectedAgents.push(s.name);
        break;
      }
    }
  }

  category = 'auto_routed';
  rationale = `Selected based on query relevance: ${selectedAgents.map(n => AGENTS[n].domain).join(', ')}`;
}

const profiles = selectedAgents.map(name => ({
  name,
  ...AGENTS[name]
}));

return {
  ...$input.first().json,
  selectedAgents,
  profiles,
  category,
  rationale,
  AGENTS
};

