const input = $input.first().json;
let synthesis, debate;

try {
  const output = input.output;
  const jsonMatch = output.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    synthesis = parsed.synthesis || {};
    debate = parsed.debate || { exchanges: [] };
  }
} catch (e) {
  synthesis = { consensus: [], tensions: [], trade_offs: [], open_questions: [] };
  debate = { exchanges: [] };
}

return {
  ...input,
  synthesis,
  debate
};

const input = $input.first().json;
let judgment;

try {
  const output = input.output;
  const jsonMatch = output.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    judgment = parsed.judgment || parsed;
  }
} catch (e) {
  judgment = {
    verdict: 'Unable to parse judgment',
    rationale: 'Please review the raw output',
    call_to_action: ['Review the deliberation manually']
  };
}

return {
  ...input,
  judgment
};

const input = $input.first().json;
const { judgment, individual_reports, query, context, profiles } = input;
const format = input.options?.format || 'standard';

let script = '';

if (format === 'short') {
  // 60-second version
  script = `The council has spoken.

My verdict: ${judgment.verdict}

${judgment.rationale}

Your next step: ${judgment.call_to_action[0]}

Now act.`;

} else if (format === 'standard') {
  // 2-3 minute version
  const agentSummaries = individual_reports.map(r => 
    `${r.agent} argued: ${r.position}`
  ).join('\n\n');

  script = `I've heard the council deliberate on your question.

${agentSummaries}

${judgment.core_tension ? `The core tension: ${judgment.core_tension}` : ''}

My judgment: ${judgment.verdict}

Here's why: ${judgment.rationale}

${judgment.uncertainty ? `What remains uncertain: ${judgment.uncertainty}` : ''}

Your next steps:
${judgment.call_to_action.map((a, i) => `${i + 1}. ${a}`).join('\n')}

The decision is yours. But if you ask what wisdom counsels—this is it.`;

} else {
  // Full 4-5 minute version
  const agentDetails = individual_reports.map(r => 
    `${r.agent}, bringing ${profiles.find(p => p.name === r.agent)?.domain || 'expertise'}, argued: ${r.position}. ${r.analysis}`
  ).join('\n\n');

  const deeperQuestion = context?.subtext?.deeper_question;
  const fear = context?.subtext?.fear;

  script = `The council convened to address this question: ${query}

${deeperQuestion ? `But the deeper question you're wrestling with is: ${deeperQuestion}\n` : ''}

I heard from three advisors:

${agentDetails}

${judgment.acknowledgments ? `${judgment.acknowledgments}` : ''}

${judgment.core_tension ? `The fundamental tension: ${judgment.core_tension}` : ''}

${judgment.stoic_principle ? `The principle that guides us: ${judgment.stoic_principle}` : ''}

My verdict: ${judgment.verdict}

${judgment.rationale}

${judgment.uncertainty ? `What I don't know: ${judgment.uncertainty}` : ''}

Here are your next steps:
${judgment.call_to_action.map((a, i) => `${i + 1}. ${a}`).join('\n')}

${fear ? `I note your fear: ${fear}. Do not let fear choose for you.` : ''}

The decision is yours. But if you ask what wisdom counsels—this is it.

Now act.`;
}

// Clean up the script
script = script.replace(/\n{3,}/g, '\n\n').trim();

return {
  ...input,
  speech_script: script,
  character_count: script.length,
  estimated_duration_seconds: Math.round(script.length / 14) // ~14 chars per second for speech
};

const items = $input.all();
const mainData = items.find(i => i.json.deliberation_id)?.json || items[0].json;
const audioData = items.find(i => i.json.id && i.json.webViewLink)?.json;

return {
  ...mainData,
  audio_url: audioData?.webViewLink || null,
  audio_id: audioData?.id || null
};

const input = $input.first().json;

// Get data from the workflow context
const mainData = $('Merge Audio Data').first().json;
const videoData = input.data?.video_url ? input : null;

const processing_time_ms = Date.now() - mainData.start_time;

return {
  success: true,
  deliberation_id: mainData.deliberation_id,
  query: mainData.query,

  panel: {
    agents: mainData.profiles.map(p => p.name),
    category: mainData.category,
    rationale: mainData.rationale
  },

  phases: mainData.options.include_full_deliberation ? {
    individual_reports: mainData.individual_reports,
    synthesis: mainData.synthesis,
    debate: mainData.debate,
    judgment: mainData.judgment
  } : {
    judgment: mainData.judgment
  },

  delivery: {
    type: mainData.options.delivery,
    audio_url: mainData.audio_url || null,
    video_url: videoData?.data?.video_url || null,
    transcript: mainData.speech_script,
    duration_seconds: mainData.estimated_duration_seconds
  },

  metadata: {
    generated_at: new Date().toISOString(),
    processing_time_ms,
    format: mainData.options.format
  }
};

// Text-only path - skip audio generation
const input = $input.first().json;

return {
  ...input,
  audio_url: null,
  audio_id: null
};

// Skip video - pass through
const input = $input.first().json;

return input;
